import{_ as o,o as t,c as i,ag as a}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"ADR-004: Must-login để book tour (không guest checkout)","description":"","frontmatter":{},"headers":[],"relativePath":"02-kien-truc/decisions/ADR-004-must-login.md","filePath":"02-kien-truc/decisions/ADR-004-must-login.md"}'),n={name:"02-kien-truc/decisions/ADR-004-must-login.md"};function r(c,e,l,h,d,s){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="adr-004-must-login-đe-book-tour-khong-guest-checkout" tabindex="-1">ADR-004: Must-login để book tour (không guest checkout) <a class="header-anchor" href="#adr-004-must-login-đe-book-tour-khong-guest-checkout" aria-label="Permalink to &quot;ADR-004: Must-login để book tour (không guest checkout)&quot;">​</a></h1><ul><li><strong>Status</strong>: Accepted</li><li><strong>Ngày</strong>: 2026-05-26</li><li><strong>Người duyệt</strong>: Founder</li></ul><hr><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Câu hỏi &quot;có cho guest checkout không?&quot; xuất hiện sớm trong design. Trade-off:</p><table tabindex="0"><thead><tr><th>Có guest checkout</th><th>Bắt buộc login</th></tr></thead><tbody><tr><td>Giảm friction → conversion cao hơn</td><td>Friction cao hơn → drop-off chỗ &quot;Pick date → Login&quot;</td></tr><tr><td>Khó verify identity → fake booking</td><td>Verify identity rõ ràng</td></tr><tr><td>Khó build loyalty</td><td>Loyalty trực tiếp từ ngày 1</td></tr><tr><td>Email dispute khó vì không có account</td><td>Account-based dispute, dễ tracking</td></tr><tr><td>Review không verified được</td><td>Review verified (linked với booking)</td></tr><tr><td>Schema <code>Booking.userId</code> nullable</td><td><code>Booking.userId</code> NOT NULL — sạch hơn</td></tr></tbody></table><hr><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Phase 1 bắt buộc login để book tour. Không guest checkout.</strong></p><p>Cụ thể:</p><ol><li><code>Booking.userId</code> NOT NULL trong schema</li><li>Middleware redirect tới <code>/auth/login</code> khi click &quot;Thanh toán&quot; mà chưa login</li><li>Login flow preserve state (departure, options đã chọn) bằng <code>?from=&lt;encoded&gt;&amp;action=book&amp;departureId=...</code></li><li>Hỗ trợ Google OAuth 1-click để giảm friction (Persona Anh Khoa &amp; Chị Linh đều quen Google)</li><li>Pre-fill booking form từ <code>Profile.displayName</code>, <code>email</code>, <code>phone</code> để giảm thao tác</li></ol><hr><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="tot" tabindex="-1">Tốt <a class="header-anchor" href="#tot" aria-label="Permalink to &quot;Tốt&quot;">​</a></h3><ul><li><strong>Loyalty từ ngày 1</strong>: mọi booking có userId → repeat rate trackable</li><li><strong>Verified review</strong>: chỉ user có <code>Booking.status=COMPLETED</code> mới review được</li><li><strong>Dispute resolution dễ</strong>: khách + admin có lịch sử booking đầy đủ qua account</li><li><strong>Fake booking giảm</strong>: spam booking khó hơn vì cần email verify hoặc Google OAuth</li><li><strong>Email transactional chuẩn</strong>: gửi đúng email account, không nhập sai</li><li><strong>Schema sạch</strong>: <code>Booking.userId</code> không nullable → query đơn giản</li></ul><h3 id="trade-off" tabindex="-1">Trade-off <a class="header-anchor" href="#trade-off" aria-label="Permalink to &quot;Trade-off&quot;">​</a></h3><ul><li><strong>Drop-off chỗ login</strong>: dự kiến 5-15% khách bỏ ngang ở bước login (industry benchmark)</li><li><strong>Khách lần đầu không thấy &quot;test booking flow&quot;</strong> trước khi register</li></ul><h3 id="mitigation-cho-drop-off" tabindex="-1">Mitigation cho drop-off <a class="header-anchor" href="#mitigation-cho-drop-off" aria-label="Permalink to &quot;Mitigation cho drop-off&quot;">​</a></h3><ul><li>Google OAuth 1-click (đa số khách đã có Google account)</li><li>Email register quick: chỉ cần email + password, không yêu cầu phone ở bước register</li><li>Save trip wishlist không cần login (Phase 1.5) — chỉ booking cần</li><li>A/B test login screen Phase 1.5 nếu conversion &lt; target</li></ul><hr><h2 id="alternatives-đa-can-nhac" tabindex="-1">Alternatives đã cân nhắc <a class="header-anchor" href="#alternatives-đa-can-nhac" aria-label="Permalink to &quot;Alternatives đã cân nhắc&quot;">​</a></h2><h3 id="a-guest-checkout-voi-email-verify-rejected" tabindex="-1">A. Guest checkout với email verify (rejected) <a class="header-anchor" href="#a-guest-checkout-voi-email-verify-rejected" aria-label="Permalink to &quot;A. Guest checkout với email verify (rejected)&quot;">​</a></h3><ul><li>Phải build dual flow (guest + login) → schema + service phức tạp</li><li>Booking history cho khách quên password vẫn cần tìm theo email — fragile</li><li>Loyalty Phase 1.5 phải migrate guest→account → đau</li></ul><h3 id="b-magic-link-passwordless-cho-phase-1-defer" tabindex="-1">B. Magic link (passwordless) cho Phase 1 (defer) <a class="header-anchor" href="#b-magic-link-passwordless-cho-phase-1-defer" aria-label="Permalink to &quot;B. Magic link (passwordless) cho Phase 1 (defer)&quot;">​</a></h3><ul><li>UX tốt nhưng phụ thuộc email delivery (spam folder)</li><li>Phase 1.5 cân nhắc nếu conversion login thấp</li></ul><h3 id="c-login-modal-inline-khong-redirect-defer" tabindex="-1">C. Login modal inline (không redirect) (defer) <a class="header-anchor" href="#c-login-modal-inline-khong-redirect-defer" aria-label="Permalink to &quot;C. Login modal inline (không redirect) (defer)&quot;">​</a></h3><ul><li>UX mượt hơn nhưng dev effort cao</li><li>Phase 1 redirect đơn giản chấp nhận trade-off</li></ul><hr><h2 id="he-qua-ky-thuat" tabindex="-1">Hệ quả kỹ thuật <a class="header-anchor" href="#he-qua-ky-thuat" aria-label="Permalink to &quot;Hệ quả kỹ thuật&quot;">​</a></h2><ul><li><code>BookingService.createTourBooking()</code> đầu tiên check <code>requireUser()</code> → throw <code>UnauthorizedError</code> nếu không login</li><li>Middleware bắt route <code>/tours/[slug]</code> với query <code>?book=1</code> → redirect login nếu chưa</li><li>Cookie public 30 days TTL (xem <code>02-cross-cutting.md</code>)</li><li>Phase 1.5: add &quot;Quick guest form&quot; cho khách lazy nhập, sau confirm tạo account auto</li></ul><hr><h2 id="lien-ket" tabindex="-1">Liên kết <a class="header-anchor" href="#lien-ket" aria-label="Permalink to &quot;Liên kết&quot;">​</a></h2><ul><li>Vision Non-Goals: <code>../../00-san-pham/01-tam-nhin.md</code></li><li>Auth flow: <code>../02-cross-cutting.md</code> mục Auth</li><li>Personas drop-off risk: <code>../../00-san-pham/03-personas-user-journey.md</code> mục Hotspot</li><li>Anchor cũ trace: V-04</li></ul>',33)])])}const k=o(n,[["render",r]]);export{g as __pageData,k as default};
